# ---------------------------------------------------------------------------
# Service Under Test (simplified implementation for testability)
# ---------------------------------------------------------------------------

class SSOAuthService:
    REQUIRED_CLAIMS = {"sub", "email", "given_name", "family_name", "patient_role"}

    def __init__(
        self,
        sso_provider: ISSOProvider,
        patient_repo: IPatientRepository,
        notification_service: INotificationService,
        rate_limiter: IRateLimiter,
        session_store: ISessionStore,
        policy: RateLimitPolicy = None,
    ):
        self._sso = sso_provider
        self._repo = patient_repo
        self._notify = notification_service
        self._rate_limiter = rate_limiter
        self._sessions = session_store
        self._policy = policy or RateLimitPolicy()

    def login_with_sso(self, token: SSOToken) -> LoginAttemptResult:
        identifier = token.email or token.id_token[:16]

        # 1. Rate-limit check BEFORE any processing
        blocked, retry_after = self._rate_limiter.is_blocked(identifier)
        if blocked:
            return LoginAttemptResult(
                success=False,
                auth_state=AuthState.LOCKED,
                error_code="RATE_LIMITED",
                error_message="Too many failed attempts.",
                retry_after_seconds=retry_after,
            )

        try:
            # 2. Validate token with IdP
            claims = self._sso.validate_token(token)

            # 3. Check required claims
            missing = self.REQUIRED_CLAIMS - set(claims.keys())
            if missing:
                raise MissingClaimError(list(missing))

            # 4. Fetch or create patient record
            patient = self._repo.upsert_patient(claims)

            # 5. Check account state
            account_state = self._repo.get_account_state(patient["id"])
            if account_state == AuthState.SUSPENDED:
                raise AccountSuspendedError("Account suspended.")
            if account_state == AuthState.LOCKED:
                raise ConflictingStateError("Account is locked.")
            if account_state == AuthState.PASSWORD_RESET_REQUIRED:
                raise ConflictingStateError("Password reset required before SSO login.")

            # 6. Permission check — must have patient_role
            if "patient" not in claims.get("patient_role", []):
                raise PermissionDeniedError("User lacks patient role.")

            # 7. Success — create session and reset rate limiter
            session_token = self._sessions.create_session(patient["id"], claims)
            self._rate_limiter.reset(identifier)

            return LoginAttemptResult(
                success=True,
                auth_state=AuthState.AUTHENTICATED,
                session_token=session_token,
            )

        except (
            InvalidTokenError,
            MissingClaimError,
            PermissionDeniedError,
            AccountSuspendedError,
            ConflictingStateError,
        ) as exc:
            # Record failure and potentially notify
            attempt_info = self._rate_limiter.record_failed_attempt(identifier)
            attempts = attempt_info.get("attempt_count", 1)
            notification_sent = False

            if attempts >= self._policy.notification_threshold:
                self._notify.send_login_failure_alert(identifier, attempts)
                notification_sent = True

            if attempts >= self._policy.max_attempts:
                unlock_at = datetime.utcnow() + timedelta(
                    seconds=self._policy.lockout_duration_seconds
                )
                self._notify.send_lockout_notification(identifier, unlock_at)

            return LoginAttemptResult(
                success=False,
                auth_state=AuthState.UNAUTHENTICATED,
                error_code=type(exc).__name__.upper().replace("ERROR", "_ERROR"),
                error_message=str(exc),
                notification_sent=notification_sent,
                remaining_attempts=max(0, self._policy.max_attempts - attempts),
            )

    def exchange_code_and_login(self, code: str, provider: SSOProvider) -> LoginAttemptResult:
        token = self._sso.exchange_code(code, provider)
        return self.login_with_sso(token)


