class TestSSOLoginSuccess:
    """Verify that a patient can successfully log in via SSO."""

    def test_successful_login_returns_session_token(
        self, auth_service, mock_sso_provider, mock_patient_repo,
        mock_session_store, valid_sso_token, valid_claims, registered_patient
    ):
        mock_sso_provider.validate_token.return_value = valid_claims
        mock_patient_repo.upsert_patient.return_value = registered_patient
        mock_patient_repo.get_account_state.return_value = AuthState.UNAUTHENTICATED

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.success is True
        assert result.auth_state == AuthState.AUTHENTICATED
        assert result.session_token is not None
        assert result.error_code is None

    def test_successful_login_resets_rate_limiter(
        self, auth_service, mock_sso_provider, mock_patient_repo,
        mock_rate_limiter, valid_sso_token, valid_claims, registered_patient
    ):
        mock_sso_provider.validate_token.return_value = valid_claims
        mock_patient_repo.upsert_patient.return_value = registered_patient

        auth_service.login_with_sso(valid_sso_token)

        mock_rate_limiter.reset.assert_called_once_with(valid_sso_token.email)

    def test_successful_login_calls_session_store_with_patient_id(
        self, auth_service, mock_sso_provider, mock_patient_repo,
        mock_session_store, valid_sso_token, valid_claims, registered_patient
    ):
        mock_sso_provider.validate_token.return_value = valid_claims
        mock_patient_repo.upsert_patient.return_value = registered_patient

        auth_service.login_with_sso(valid_sso_token)

        mock_session_store.create_session.assert_called_once_with(
            registered_patient["id"], valid_claims
        )

    @pytest.mark.parametrize("provider", list(SSOProvider))
    def test_all_supported_sso_providers_succeed(
        self, auth_service, mock_sso_provider, mock_patient_repo,
        valid_claims, registered_patient, provider
    ):
        token = SSOToken(
            provider=provider,
            id_token="tok",
            access_token="acc",
            email="patient@example.com",
        )
        mock_sso_provider.validate_token.return_value = valid_claims
        mock_patient_repo.upsert_patient.return_value = registered_patient

        result = auth_service.login_with_sso(token)

        assert result.success is True

    def test_successful_login_does_not_send_failure_notification(
