class TestRateLimiting:
    """Verify rate-limiting enforcement and patient notification on repeated failures."""

    def test_blocked_identifier_returns_rate_limited_error(
        self, auth_service, mock_rate_limiter, valid_sso_token
    ):
        mock_rate_limiter.is_blocked.return_value = (True, 600)

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.success is False
        assert result.error_code == "RATE_LIMITED"
        assert result.auth_state == AuthState.LOCKED
        assert result.retry_after_seconds == 600

    def test_rate_limited_response_includes_retry_after(
        self, auth_service, mock_rate_limiter, valid_sso_token
    ):
        mock_rate_limiter.is_blocked.return_value = (True, 300)

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.retry_after_seconds == 300

    def test_rate_limiter_checked_before_token_validation(
        self, auth_service, mock_rate_limiter, mock_sso_provider, valid_sso_token
    ):
        mock_rate_limiter.is_blocked.return_value = (True, 100)

        auth_service.login_with_sso(valid_sso_token)

        mock_sso_provider.validate_token.assert_not_called()

    def test_failed_attempt_recorded_on_invalid_token(
        self, auth_service, mock_sso_provider, mock_rate_limiter, valid_sso_token
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("expired")
        mock_rate_limiter.record_failed_attempt.return_value = {"attempt_count": 1}

        auth_service.login_with_sso(valid_sso_token)

        mock_rate_limiter.record_failed_attempt.assert_called_once_with(
            valid_sso_token.email
        )

    def test_notification_sent_after_threshold_failures(
        self, auth_service, mock_sso_provider, mock_rate_limiter,
        mock_notification_service, valid_sso_token, rate_policy
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")
        mock_rate_limiter.record_failed_attempt.return_value = {
            "attempt_count": rate_policy.notification_threshold
        }

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.notification_sent is True
        mock_notification_service.send_login_failure_alert.assert_called_once_with(
            valid_sso_token.email, rate_policy.notification_threshold
        )

    def test_no_notification_before_threshold_failures(
        self, auth_service, mock_sso_provider, mock_rate_limiter,
        mock_notification_service, valid_sso_token, rate_policy
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")
        mock_rate_limiter.record_failed_attempt.return_value = {
            "attempt_count": rate_policy.notification_threshold - 1
        }

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.notification_sent is False
        mock_notification_service.send_login_failure_alert.assert_not_called()

    def test_lockout_notification_sent_on_max_failures(
        self, auth_service, mock_sso_provider, mock_rate_limiter,
        mock_notification_service, valid_sso_token, rate_policy
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")
        mock_rate_limiter.record_failed_attempt.return_value = {
            "attempt_count": rate_policy.max_attempts
        }

        auth_service.login_with_sso(valid_sso_token)

        mock_notification_service.send_lockout_notification.assert_called_once()
        call_args = mock_notification_service.send_lockout_notification.call_args
        assert call_args[0][0] == valid_sso_token.email
        unlock_at = call_args[0][1]
        assert isinstance(unlock_at, datetime)

    def test_remaining_attempts_decrements_correctly(
        self, auth_service, mock_sso_provider, mock_rate_limiter,
        valid_sso_token, rate_policy
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")
        mock_rate_limiter.record_failed_attempt.return_value = {"attempt_count": 2}

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.remaining_attempts == rate_policy.max_attempts - 2

    def test_remaining_attempts_is_zero_not_negative_at_lockout(
        self, auth_service, mock_sso_provider, mock_rate_limiter,
        valid_sso_token, rate_policy
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")
        mock_rate_limiter.record_failed_attempt.return_value = {
            "attempt_count": rate_policy.max_attempts + 2
        }

        result = auth_service.login_with_sso(valid_sso_token)

        assert result.remaining_attempts == 0

    def test_rate_limiter_not_reset_on_failure(
        self, auth_service, mock_sso_provider, mock_rate_limiter, valid_sso_token
    ):
        mock_sso_provider.validate_token.side_effect = InvalidTokenError("bad token")

        auth_service.login_with_sso(valid_sso_token)

        mock_rate_limiter.reset.assert_not_called()


